const body = $input.first().json.body;
const { listId, description, count, detail } = body;

const detailMap = {
  kurz: 'Kurze, prägnante Aufgaben (max 6 Wörter pro Aufgabe, keine Notizen nötig)',
  mittel: 'Klare Aufgaben mit kurzer Notiz als Hilfestellung (1 Satz)',
  detailliert: 'Ausführliche Aufgaben mit konkreten Tipps, Tools und Zeitschätzungen als Notiz'
};

const prompt = `Du bist ein erfahrener Projektmanager und Produktivitäts-Coach. Erstelle eine strukturierte ToDo-Liste basierend auf der Beschreibung. Antworte NUR mit validem JSON.

Beschreibung des Vorhabens:
"${description}"

Anforderungen:
- Anzahl Aufgaben: genau ${count} ToDos
- Detailtiefe: ${detailMap[detail] || detailMap.mittel}
- Sprache: Deutsch
- Priorisiere nach Wichtigkeit und logischer Reihenfolge

Antworte in exakt diesem JSON-Format:
{
  "title": "Kurzer, prägnanter Listentitel (max 5 Wörter)",
  "todos": [
    {
      "text": "Aufgabe (Imperativ, handlungsorientiert)",
      "note": "Hilfreiche Notiz oder Tipp (optional, nur bei mittel/detailliert)",
      "priority": "high" | "medium" | "low",
      "category": "Kategorie-Name (z.B. Planung, Technik, Finanzen)"
    }
  ]
}

Regeln:
- Aufgaben müssen KONKRET und UMSETZBAR sein (keine vagen Aussagen)
- Logische Reihenfolge beachten (was kommt zuerst?)
- Kategorien sinnvoll gruppieren (max 4-5 verschiedene Kategorien)
- priority: high = kritisch/zuerst, medium = wichtig, low = nice-to-have
- Genau ${count} todos im Array
- note: leer lassen ("") wenn detailtiefe "kurz" ist`;

return [{ json: { prompt, listId } }];

const aiText = $input.first().json.message?.content || '{}';
const listId = $('Prompt aufbauen').first().json.listId;

let parsed;
try {
  const cleaned = aiText.replace(/```json\n?/g,'').replace(/```/g,'').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { title: 'ToDo Liste', todos: [] };
}

// Validierung
if (!Array.isArray(parsed.todos)) parsed.todos = [];

const validPrios = ['high','medium','low'];

parsed.todos = parsed.todos.map((t, i) => ({
  text:     String(t.text     || '').trim(),
  note:     String(t.note     || '').trim(),
  priority: validPrios.includes(t.priority) ? t.priority : 'medium',
  category: String(t.category || 'Allgemein').trim()
})).filter(t => t.text.length > 0);

return [{ json: {
  title:  parsed.title || 'ToDo Liste',
  todos:  parsed.todos,
  listId
}}];
